import{_ as n,o as t,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"30. Superannuation","description":"","frontmatter":{"title":"30. Superannuation","eba":"Biomedical Engineers 2025-2028","topics":["wages","superannuation","preliminary"]},"headers":[],"relativePath":"ebas/biomedical-engineers/wages/30-superannuation.md","filePath":"ebas/biomedical-engineers/wages/30-superannuation.md"}'),r={name:"ebas/biomedical-engineers/wages/30-superannuation.md"};function i(s,e,p,u,l,d){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_30-superannuation" tabindex="-1">30. Superannuation <a class="header-anchor" href="#_30-superannuation" aria-label="Permalink to &quot;30. Superannuation&quot;">​</a></h1><p>The subject of superannuation is dealt with extensively by federal legislation which prescribes the obligations and entitlements regarding superannuation. This clause is ancillary to and supplements those provisions.</p><p><strong>30.1</strong> Definitions In this clause:</p><p><strong>(a)</strong> Default Fund means the Aware Super superannuation fund (or its successor) while it provides a “MySuper product” as defined by the Act.</p><p><strong>(b)</strong> Preferred Superannuation Fund means a fund that meets the definition of a superannuation fund in the Superannuation Guarantee (Administration) Act 1992 (Cth).</p><p><strong>(c)</strong> Industry Superannuation Fund means a complying superannuation fund, as defined in the Superannuation Industry (Supervision) Act 1993, that:</p><p><strong>(i)</strong> has twenty or more participating employers;</p><p><strong>(ii)</strong> excluding any independent directors, provides for half of the trustee board to be comprised of employee representatives and/or nominated by one or more</p><p>trade unions and half of the trustee board to be comprised of representatives of participating employers; and</p><p><strong>(iii)</strong> operates on a “not for profit” basis.</p><p><strong>30.2</strong> Superannuation contributions The Employer will make superannuation contributions on behalf of an Employee to any of the following superannuation funds nominated by an Employee:</p><p><strong>(a)</strong> HESTA (Health Employees Superannuation Trust of Australia) or successor;</p><p><strong>(b)</strong> Aware Super (Aware Super Pty Ltd), or successor;</p><p><strong>(c)</strong> the Employee’s preferred superannuation fund where it is an Industry Superannuation Fund; or</p><p><strong>(d)</strong> where relevant superannuation legislation requires choice of superannuation fund in an enterprise agreement, any other Preferred Superannuation Fund nominated by the Employee.</p><p><strong>30.3</strong> New Employee does not nominate fund If the Employee does not nominate a fund, the Employer will pay the Employee&#39;s superannuation contributions to the Default Fund, or where required by superannuation legislation to the Employee’s stapled superannuation fund.</p><p><strong>30.4</strong> Calculation of superannuation contributions Superannuation contributions paid by the Employer will be calculated and paid on:</p><p><strong>(a)</strong> ordinary time earnings as defined in the Superannuation Guarantee (Administration) Act 1992 (Cth), calculated on the Employee’s pre salary packaging earnings;</p><p><strong>(b)</strong> any additional amounts consistent with the trust deed of the superannuation fund; and</p><p><strong>(c)</strong> a period of paid parental leave until the FFPPOOA the commencement of this Agreement in accordance with subclause 30.5(c) of the 2022 Agreement, after which superannuation shall be paid on parental leave (paid and unpaid) in accordance with subclause 30.6.</p><p><strong>30.5</strong> Voluntary Employee Contributions</p><p><strong>(a)</strong> An Employee may, in writing, authorise their Employer to pay on behalf of the Employee a specified amount from the post-taxation wages of the Employee.</p><p><strong>(b)</strong> An Employee may adjust the amount the Employer authorises the Employer to pay from their wages from the first of the month following the giving of three (3) months’ written notice to the Employer.</p><p><strong>(c)</strong> The Employer must pay the amount authorised under subclauses 30.5(a) or (b) no later than 28 days after the end of the month in which the authorised deduction was made.</p><p><strong>30.6</strong> Superannuation during parental leave - from the FFPPOOA the commencement of this Agreement</p><p><strong>(a)</strong> From the FFPPOOA the commencement of this Agreement, the Employer will make superannuation contributions throughout any period of parental leave, paid or unpaid.</p><p><strong>(b)</strong> Such contributions will be calculated as follows:</p><p><strong>(i)</strong> the Employee&#39;s ordinary time earnings as defined in the Superannuation Guarantee (Administration) Act 1992 (Cth) calculated on the Employee&#39;s pre- salary packaging earnings and any additional amounts consistent with the trust deed of the superannuation fund over 26 full pay periods (that is over 52 weeks) immediately prior to commencing parental leave and divided by 52 (Weekly Parental Leave Super Contribution);</p><p><strong>(ii)</strong> the Weekly Parental Leave Super Contribution will be paid during each week of Parental Leave (both paid and unpaid) save that: <strong>(A)</strong> the Employee will receive a pro rata payment for a period less than one (1) week; and <strong>(B)</strong> where, during the period of parental leave (either paid or unpaid), the Employee&#39;s rate of pay increases under subclause 26.1, the Employee&#39;s pre-salary packaging earnings as calculated above will be increased accordingly from the relevant date and superannuation paid on the increased amount.</p><p>Plain language terms: super, SG.</p>',30)])])}const c=n(r,[["render",i]]);export{m as __pageData,c as default};
